  ('customs-7fec267e-moex-00339', 'customs-7fec267e', 'customs-7fec267e-moex-110-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '下列有關賽局理論中「囚犯困境」（Prisoners''Dilemma）的敘述，何者正確？', '["描述犯罪嫌疑犯們可能要在獄中服刑，無法逃離監獄的困境", "描述犯罪嫌疑犯們採取對自身有利的辯詞，但可能陷入讓大家都受害的困境", "描述犯罪嫌疑犯們面對員警刑求時，是否要說真話的困境", "描述犯罪嫌疑犯後悔已經從事犯罪行為的困境"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "5bec6315ccf2", "answer_pdf_sha1": "c6a2f8035359", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "141", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00340', 'customs-7fec267e', 'customs-7fec267e-moex-110-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '有貿易關係的A國與C國發生貿易摩擦，因此兩國都提高對方進口產品的關稅，下列何者正確？', '["A國的消費者剩餘上升", "A國的生產者剩餘上升", "A國的社會福利上升", "兩國的貿易量上升"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "5bec6315ccf2", "answer_pdf_sha1": "c6a2f8035359", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "141", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00341', 'customs-7fec267e', 'customs-7fec267e-moex-110-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '關於規模經濟（economiesofscale）的敘述，下列何者錯誤？', '["小型經濟體為了追求規模經濟，往往採納更開放的貿易政策", "顯著的規模經濟是造成市場結構出現獨占者的原因之一", "規模經濟又稱為學習效果，是因為生產過程中犯錯減少而使生產成本降低", "規模經濟的定義為廠商在生產過程中，隨著產量的增加，平均成本逐漸下降"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "5bec6315ccf2", "answer_pdf_sha1": "c6a2f8035359", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "141", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00342', 'customs-7fec267e', 'customs-7fec267e-moex-110-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設一消費者消費X與Y兩種財貨，其預算線如下圖bc線段，無異曲線與預算線相切於a點。若兩 財貨價格不變下，所得增加5元時，消費者會選擇d點，則下列敘述何者錯誤？', '["d點的效用水準較a點高", "a點與d點的邊際替代率相等", "X與Y均為正常財", "最適消費點由a點變動到d點之總效果可分解為所得效果與替代效果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "5bec6315ccf2", "answer_pdf_sha1": "c6a2f8035359", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "141", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00343', 'customs-7fec267e', 'customs-7fec267e-moex-110-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '在國際貿易模型的圖形中，一國利用其生產可能前緣（ProductionPossibilityFrontier）曲線決定出其 生產點，再透過國際價格與他國交易，達到最後的消費點。有關生產點與消費點之間的敘述，下列何 者正確？', '["生產點位於生產可能前緣曲線上、消費點位於生產可能前緣曲線上", "生產點位於生產可能前緣曲線外、消費點位於生產可能前緣曲線上", "生產點位於生產可能前緣曲線上、消費點位於生產可能前緣曲線外", "生產點位於生產可能前緣曲線外、消費點位於生產可能前緣曲線外"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "5bec6315ccf2", "answer_pdf_sha1": "c6a2f8035359", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "141", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00344', 'customs-7fec267e', 'customs-7fec267e-moex-110-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '某甲一天可捕10斤的魚貨或是織10尺的布匹，某乙一天只能捕8斤的魚貨或是織4尺的布匹。請 問甲、乙兩人各捕1斤魚貨的機會成本加總起來是多少？', '["1/2尺布匹", "1尺布匹", "3/2尺布匹", "2尺布匹"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "5bec6315ccf2", "answer_pdf_sha1": "c6a2f8035359", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "141", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00345', 'customs-7fec267e', 'customs-7fec267e-moex-110-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '牛奶的市場需求函數為：Q =100–3P+2P，其中P 為豆漿的市場價格。牛奶的需求對於豆漿價格 D S S 的交叉價格彈性為：', '["–3", "–2", "–3/2", "資訊不足，無法得知"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "5bec6315ccf2", "answer_pdf_sha1": "c6a2f8035359", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "141", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL)
